#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long x,id;
    bool operator<(const node&b)const
    {
        return x>b.x;
    }
}a[500010];
long long s[500010],ans[500010];
int main()
{
    long long n,k;
    scanf("%lld",&n);
    scanf("%lld%lld",&n,&k);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i].x);
        a[i].id=i;
    }
    sort(a+1,a+1+n);
    for(long long i=1;i<=n;i++)
    {
        s[i]=s[i-1]+a[i].x;
    }
    for(long long i=1;i<=n;i++)
    {
        if(a[i].x==a[k].x)
        {
            ans[a[i].id]=0;
        }
        else if(a[i].x<a[k].x)
        {
            ans[a[i].id]=a[k].x-a[i].x;
        }
        else
        {
            ans[a[i].id]=1ll*(k-i)*a[i].x-s[k]+s[i];
        }
    }
    for(long long i=1;i<=n;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
